380	test('drain-queue golden: typed-error completion records a reason on the bead', async ({ page }) => {
381		const state: { workers: WorkerNode[]; dispatched: { count: number } } = {
382			workers: [
383				makeWorker({
384					state: 'done',
385					status: 'no-viable-provider',
386					attempts: 1,
387					successes: 0,
388					failures: 1,
389					finishedAt: '2026-04-29T12:05:00Z',
390					lastError: 'no-viable-provider: all 4 endpoints exhausted; bead-001 marked failed with reason'
391				})
392			],
393			dispatched: { count: 0 }
394		};
395		await installGraphqlMocks(page, state);
396	
397		await page.goto(WORKERS_URL);
398		await expect(page.getByRole('heading', { name: 'Workers' })).toBeVisible();
399	
400		const final = state.workers[0];
401		// Typed error (not the string "error") with a non-empty reason on the bead.
402		expect(final.status).not.toBe('error');
403		expect(final.status).not.toBeNull();
404		expect((final.status ?? '').length).toBeGreaterThan(0);
405		expect((final.lastError ?? '').length).toBeGreaterThan(0);
406		expect(final.lastError ?? '').toMatch(/reason/i);
407	
408		// Attempts count still matches work done; never the 19-failure pattern.
409		expect(attemptsMatchWorkDone(final)).toBe(true);
410		expect(final.failures).not.toBe(19);
411	
412		// The harness model — even on failure — is bound to a live endpoint and
413		// not a gemini-cross-pollinated pairing.
414		expect(harnessBoundToLiveEndpoint(final)).toBe(true);
415		expect(noGeminiCrossContamination(final)).toBe(true);
416	});
